import { writeFile } from 'node:fs/promises';
import { join } from 'node:path';
import type { StackInfo } from '../analyzers/stack-detector.js';

function getGeminiRules(stack: StackInfo): string {
  const lines: string[] = [
    '# Project AI Rules — Generated by ContextSlim',
    '',
    '> These rules help AI assistants understand your project better and reduce token waste.',
    '',
    '## General Guidelines',
    '',
    '- **Be concise**: Don\'t repeat code that already exists in the project.',
    '- **Be modular**: Write small, focused functions with clear responsibilities.',
    '- **Follow existing patterns**: Match the coding style and conventions already used in this project.',
    '- **No unnecessary comments**: Only add comments for complex logic, not obvious code.',
    '- **Prefer edits over rewrites**: When modifying code, show only the changed parts, not the entire file.',
    '',
  ];

  // Stack-specific rules
  if (stack.language === 'TypeScript' || stack.language === 'JavaScript') {
    lines.push(
      '## Stack: ' + stack.name,
      '',
      '- Use **ES Modules** (`import`/`export`) — not CommonJS (`require`).',
      '- Prefer `const` over `let`. Never use `var`.',
      '- Use **async/await** over raw Promises or callbacks.',
      '- Use optional chaining (`?.`) and nullish coalescing (`??`).',
      '- Handle errors with try/catch, not `.catch()` chains.',
    );
    
    // Framework-specific rules
    if (stack.frameworks && stack.frameworks.length > 0) {
      if (stack.frameworks.includes('React') || stack.frameworks.includes('Next.js')) {
        lines.push(
          '- Write functional React components using hooks.',
          '- Avoid class components unless strictly necessary.',
          '- Keep effect dependencies accurate.',
        );
      }
      if (stack.frameworks.includes('Next.js')) {
        lines.push(
          '- Use Next.js App Router conventions if applicable (`page.tsx`, `layout.tsx`).',
          '- Optimize images with `next/image`.',
        );
      }
      if (stack.frameworks.includes('NestJS')) {
        lines.push(
          '- Follow NestJS dependency injection patterns.',
          '- Use decorators correctly for controllers, services, and modules.',
        );
      }
      if (stack.frameworks.includes('Vue') || stack.frameworks.includes('Nuxt')) {
        lines.push(
          '- Use script setup for Vue 3 Composition API.',
          '- Prefer refs and reactive objects for state management.',
        );
      }
    }

    if (stack.hasTypeScript) {
      lines.push(
        '- Define explicit **TypeScript types** for function parameters and return values.',
        '- Use `interface` for object shapes, `type` for unions and intersections.',
        '- Enable and respect **strict mode** in tsconfig.',
        '- Avoid `any` — use `unknown` when the type is truly uncertain.',
      );
    }
  } else if (stack.language === 'Python') {
    lines.push(
      '## Stack: ' + stack.name,
      '',
      '- Use **type hints** for all function signatures.',
      '- Follow **PEP 8** style conventions.',
      '- Use **f-strings** for string formatting.',
      '- Prefer **pathlib** over os.path for file operations.',
      '- Use **dataclasses** or **Pydantic** for structured data.',
      '- Handle exceptions specifically — avoid bare `except:`.',
    );
  } else if (stack.language === 'Rust') {
    lines.push(
      '## Stack: ' + stack.name,
      '',
      '- Follow **Rust idioms**: use `Result<T, E>` for error handling.',
      '- Prefer **iterators** and functional patterns over manual loops.',
      '- Use `clippy` suggestions and `rustfmt` formatting.',
      '- Minimize `.unwrap()` and `.expect()` — propagate errors with `?`.',
      '- Document public APIs with `///` doc comments.',
    );
  } else if (stack.language === 'Go') {
    lines.push(
      '## Stack: ' + stack.name,
      '',
      '- Follow **Go conventions**: naming, package structure, error handling.',
      '- Always check and handle errors explicitly.',
      '- Use `context.Context` for cancellation and timeouts.',
      '- Prefer standard library packages when possible.',
    );
  } else {
    lines.push(
      '## Stack: ' + stack.name,
      '',
      '- Follow the language\'s idiomatic conventions.',
      '- Keep code DRY (Don\'t Repeat Yourself).',
      '- Write clear, self-documenting code.',
    );
  }

  lines.push(
    '',
    '## Project Structure',
    '',
    '- Respect the existing directory layout.',
    '- Create new files in the appropriate directories.',
    '- Keep related functionality together.',
    '',
    '---',
    '',
    '*Auto-generated by [ContextSlim](https://github.com/contextslim/contextslim) — save tokens, ship faster.*',
    '',
  );

  return lines.join('\n');
}

function getAgentsRules(stack: StackInfo): string {
  const lines: string[] = [
    '# Agent Behavior Rules — Generated by ContextSlim',
    '',
    '> Instructions for AI coding agents working on this project.',
    '',
    '## Context Management',
    '',
    '- Read only the files relevant to the current task.',
    '- Don\'t scan entire directory trees unless absolutely necessary.',
    '- Use file search and grep before reading large files.',
    '- Prefer reading specific line ranges over full files.',
    '',
    '## Code Modification',
    '',
    '- Make **minimal, focused changes** — don\'t refactor unrelated code.',
    '- Always verify your changes compile/pass linting before submitting.',
    '- When adding new features, follow the established patterns in this codebase.',
    '- Add appropriate error handling for new code paths.',
    '',
    '## Communication',
    '',
    '- Explain *why* you made a change, not just *what* you changed.',
    '- If unsure about a design decision, ask before implementing.',
    '- Flag any potential breaking changes explicitly.',
    '',
  ];

  if (stack.language === 'TypeScript' || stack.language === 'JavaScript') {
    lines.push(
      '## Stack-Specific (' + stack.name + ')',
      '',
      '- Run `npm run build` to verify TypeScript compilation.',
      '- Check for lint errors before finishing a task.',
      '- Use existing npm scripts — don\'t create ad-hoc commands.',
      '',
    );
  } else if (stack.language === 'Python') {
    lines.push(
      '## Stack-Specific (' + stack.name + ')',
      '',
      '- Run tests with `pytest` or the project\'s test command.',
      '- Check types with `mypy` if configured.',
      '- Use virtual environment — don\'t install packages globally.',
      '',
    );
  } else if (stack.language === 'Rust') {
    lines.push(
      '## Stack-Specific (' + stack.name + ')',
      '',
      '- Run `cargo check` before submitting changes.',
      '- Run `cargo clippy` for lint warnings.',
      '- Run `cargo fmt` to ensure consistent formatting.',
      '',
    );
  }

  lines.push(
    '---',
    '',
    '*Auto-generated by [ContextSlim](https://github.com/contextslim/contextslim) — save tokens, ship faster.*',
    '',
  );

  return lines.join('\n');
}

export async function generateRulesFiles(
  dir: string,
  stack: StackInfo,
): Promise<string[]> {
  const createdFiles: string[] = [];

  // Generate GEMINI.md
  const geminiContent = getGeminiRules(stack);
  await writeFile(join(dir, 'GEMINI.md'), geminiContent, 'utf-8');
  createdFiles.push('GEMINI.md');

  // Generate AGENTS.md
  const agentsContent = getAgentsRules(stack);
  await writeFile(join(dir, 'AGENTS.md'), agentsContent, 'utf-8');
  createdFiles.push('AGENTS.md');

  return createdFiles;
}
